import React, { useState, useEffect } from 'react';
import { View, Button, Text } from 'react-native';
import * as AuthSession from 'expo-auth-session';

const CLIENT_ID = 'your_client_id';
const REDIRECT_URI = AuthSession.makeRedirectUri();
const AUTHORIZATION_ENDPOINT = 'https://your-oauth-server.com/auth';
const TOKEN_ENDPOINT = 'https://your-oauth-server.com/token';

export default function App() {
  const [authToken, setAuthToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);

  useEffect(() => {
    if (refreshToken) {
      const interval = setInterval(() => {
        refreshAccessToken();
      }, 1000 * 60 * 15); // Refresh every 15 minutes
      return () => clearInterval(interval);
    }
  }, [refreshToken]);

  const handleOAuthLogin = async () => {
    const authUrl = `${AUTHORIZATION_ENDPOINT}?response_type=code&client_id=${CLIENT_ID}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}`;
    const result = await AuthSession.startAsync({ authUrl });

    if (result.type === 'success') {
      const code = result.params.code;
      exchangeCodeForToken(code);
    }
  };

  const exchangeCodeForToken = async (code) => {
    try {
      const response = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=authorization_code&code=${code}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}&client_id=${CLIENT_ID}`,
      });
      const data = await response.json();
      setAuthToken(data.access_token);
      setRefreshToken(data.refresh_token);
    } catch (error) {
      console.error('Error exchanging code for token:', error);
    }
  };

  const refreshAccessToken = async () => {
    try {
      const response = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=refresh_token&refresh_token=${refreshToken}&client_id=${CLIENT_ID}`,
      });
      const data = await response.json();
      setAuthToken(data.access_token);
    } catch (error) {
      console.error('Error refreshing access token:', error);
    }
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      {authToken ? (
        <Text>Authenticated!</Text>
      ) : (
        <Button title="Login with OAuth" onPress={handleOAuthLogin} />
      )}
    </View>
  );
}